INSERT INTO recipes (id, tenant_id, target_item_id, ingredient_item_id, quantity, unit)
SELECT
    gen_random_uuid(),
    '36246c27-51d6-4e76-9ec1-ca40491661fa',
    target_item.id,
    ingredient_item.id,
    recipe_seed.quantity,
    recipe_seed.unit
FROM recipe_seed
JOIN items target_item
  ON target_item.tenant_id = '36246c27-51d6-4e76-9ec1-ca40491661fa'
 AND target_item.name = recipe_seed.target_item_name
 AND target_item.type = 'SELLABLE'
 AND target_item.deleted_at IS NULL
JOIN items ingredient_item
  ON ingredient_item.tenant_id = '36246c27-51d6-4e76-9ec1-ca40491661fa'
 AND ingredient_item.name = recipe_seed.ingredient_name
 AND ingredient_item.type = 'INGREDIENT'
 AND ingredient_item.deleted_at IS NULL
ON CONFLICT (target_item_id, ingredient_item_id) DO NOTHING;

