,{"item_id":"3b71536d-acf5-6dd3-6d34-6a74fec5fe7f","item_name":"Syrup đường","quantity":8000,"cost_per_unit":0.02,"min_level":1500,"unit":"ml","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"5c56e8f9-0356-3613-db6c-4b0bfaa89f17","item_name":"Syrup vải","quantity":2000,"cost_per_unit":0.09,"min_level":400,"unit":"ml","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"a20e6128-338d-3d38-ca43-3ba158c45cd0","item_name":"Táo đỏ","quantity":5000,"cost_per_unit":0.03,"min_level":1200,"unit":"g","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"454255af-65b1-f084-98a8-134e589d582e","item_name":"Tắc tươi","quantity":3000,"cost_per_unit":0.018,"min_level":600,"unit":"g","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"75e3c4e4-d32b-740f-e175-426aae133610","item_name":"Thanh long đỏ","quantity":5000,"cost_per_unit":0.02,"min_level":1200,"unit":"g","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"d25dec6e-a243-f4c5-fc16-cc68a60cb6bb","item_name":"Tonic water","quantity":5000,"cost_per_unit":0.05,"min_level":1000,"unit":"ml","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"0abffda4-3735-e1c3-36c8-e32d22bbf53b","item_name":"Trân châu đen","quantity":5000,"cost_per_unit":0.03,"min_level":1000,"unit":"g","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"99fadae6-af04-d80e-6004-f0bbee3d34d8","item_name":"Trứng gà","quantity":300,"cost_per_unit":0.18,"min_level":60,"unit":"cái","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"466ca566-c534-71fd-bed0-e3939c69cafc","item_name":"Vải ngâm","quantity":3000,"cost_per_unit":0.085,"min_level":600,"unit":"g","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"c584871c-ab1f-5a8f-c9e3-855a21341dda","item_name":"Việt quất","quantity":1800,"cost_per_unit":0.14,"min_level":400,"unit":"g","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"f644e54b-8667-bf22-5270-2c6d49993fdc","item_name":"Whipping cream","quantity":4000,"cost_per_unit":0.09,"min_level":800,"unit":"ml","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"},{"item_id":"74957c1b-3b56-7eb2-e834-e87e6823db09","item_name":"Xoài chín","quantity":6000,"cost_per_unit":0.026,"min_level":1500,"unit":"g","expires_at":null,"note":"Khoi tao ton kho nguyen lieu tu menu test 2026-04-10"}]$json$::jsonb) AS x(
        item_id UUID,
        item_name TEXT,
        quantity NUMERIC,
        cost_per_unit NUMERIC,
        min_level NUMERIC,
        unit TEXT,
        expires_at TIMESTAMP,
        note TEXT
    )
),
stock_targets AS (
    SELECT
        branch.id AS branch_id,
        item.id AS item_id,
        item.name AS item_name,
        stock_seed.quantity,
        stock_seed.cost_per_unit,
        stock_seed.min_level,
        stock_seed.unit,
        stock_seed.expires_at,
        stock_seed.note
    FROM stock_seed
    JOIN items item
      ON item.tenant_id = '36246c27-51d6-4e76-9ec1-ca40491661fa'
     AND item.name = stock_seed.item_name
     AND item.type = 'INGREDIENT'
     AND item.deleted_at IS NULL
    JOIN branches branch
      ON branch.tenant_id = '36246c27-51d6-4e76-9ec1-ca40491661fa'
    WHERE NOT EXISTS (
        SELECT 1
        FROM inventory_transactions tx
        WHERE tx.branch_id = branch.id
          AND tx.item_id = item.id
          AND tx.type = 'IMPORT'
          AND tx.note = stock_seed.note
    )
),
inserted_batches AS (
    INSERT INTO stock_batches (
        id, tenant_id, branch_id, item_id, supplier_id, quantity_initial, quantity_remaining, cost_per_unit, imported_at, expires_at, created_at
    )
    SELECT
        gen_random_uuid(),
        '36246c27-51d6-4e76-9ec1-ca40491661fa',
        target.branch_id,
        target.item_id,
        NULL,
        target.quantity,
        target.quantity,
        target.cost_per_unit,
        CURRENT_TIMESTAMP,
        target.expires_at,
        CURRENT_TIMESTAMP
    FROM stock_targets target
    RETURNING id, branch_id, item_id, quantity_initial, cost_per_unit
),
upserted_balances AS (
    INSERT INTO inventory_balances (
        id, tenant_id, branch_id, item_id, item_name, unit, quantity, min_level, version, updated_at
    )
    SELECT
        gen_random_uuid(),
        '36246c27-51d6-4e76-9ec1-ca40491661fa',
        target.branch_id,
        target.item_id,
        target.item_name,
        target.unit,
        target.quantity,
        target.min_level,
        0,
        CURRENT_TIMESTAMP
    FROM stock_targets target
    ON CONFLICT (branch_id, item_id) DO UPDATE
    SET quantity = inventory_balances.quantity + EXCLUDED.quantity,
        item_name = EXCLUDED.item_name,
        unit = EXCLUDED.unit,
        min_level = GREATEST(inventory_balances.min_level, EXCLUDED.min_level),
        updated_at = CURRENT_TIMESTAMP,
        version = inventory_balances.version + 1
    RETURNING id
)
INSERT INTO inventory_transactions (
    id, tenant_id, branch_id, item_id, user_id, batch_id, type, quantity, cost_per_unit, reference_id, reference_type, note, created_at
)
SELECT
    gen_random_uuid(),
    '36246c27-51d6-4e76-9ec1-ca40491661fa',
    batch.branch_id,
    batch.item_id,
    NULL,
    batch.id,
    'IMPORT',
    batch.quantity_initial,
    batch.cost_per_unit,
    NULL,
    'MANUAL',
    'Khoi tao ton kho nguyen lieu tu menu test 2026-04-10',
    CURRENT_TIMESTAMP
FROM inserted_batches batch;

-- =============================================================================
-- XÁC NHẬN KẾT QUẢ
-- =============================================================================
SELECT 'ingredient_items' AS table_name, COUNT(*) AS record_count
FROM items
WHERE tenant_id = '36246c27-51d6-4e76-9ec1-ca40491661fa' AND type = 'INGREDIENT' AND deleted_at IS NULL
UNION ALL
SELECT 'recipes', COUNT(*)
FROM recipes r
WHERE r.tenant_id = '36246c27-51d6-4e76-9ec1-ca40491661fa'
UNION ALL
SELECT 'inventory_balances', COUNT(*)
FROM inventory_balances ib
WHERE ib.tenant_id = '36246c27-51d6-4e76-9ec1-ca40491661fa'
UNION ALL
SELECT 'inventory_transactions_init', COUNT(*)
FROM inventory_transactions it
WHERE it.tenant_id = '36246c27-51d6-4e76-9ec1-ca40491661fa'
  AND it.type = 'IMPORT'
  AND it.note = 'Khoi tao ton kho nguyen lieu tu menu test 2026-04-10';
